<template>
    <div class="padding-t_10" id="reportstabsdata">
        <div class="left-menu-tab new_tab">
            <div class="col-md-12 p-0">
                <div class="theme-primary partition">
                    <span class="p-name text-white">Project Reports</span>
                </div>
            </div>            
            <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
                <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper" role="tablist">
                    <li v-for="(tab, index) in filteredTabs" :key="index">
                        <a class="nav-link left-menu" :data-toggle="'#' + tab.id" :class="{ active: activeKey === tab.index }" @click="activateTab(tab.index)">
                            <i :class="tab.icon" aria-hidden="true"></i>{{ $t(tab.name) }}
                        </a>
                    </li>
                </ul>
            </div>
        </div>
    
        <!-- right-content here -->
        <div class="right-content">
            <loader :isVisible="isLoading"></loader>
            <div class="col-md-12 p-0">
                <div class="theme-primary partition" style="overflow: visible">
                    <span class="p-name text-white" id="spnreporttext">{{
                this.$t(activeTabName)
              }}</span>
                </div>
            </div>
            <div class="col-md-12 p-0">
                <div class="tab-content" id="myTabContent">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
                            <i class="icon-solid arrow-solid-left text-white" style="font-size: 9pt"></i>
                        </a>
                    </div>
                    <div id="OneMonthReport" :key="refreshKey" :ReportName="ReportName" class="tab-pane" :class="{ 'active show': activeKey == 0 }" v-if="activeKey == 0">
                        <OneMonthReport></OneMonthReport>
                    </div>
                    <div id="OneWeekReport" :key="refreshKey" :ReportName="ReportName" class="tab-pane" :class="{ 'active show': activeKey == 1 }" v-if="activeKey == 1">
                        <OneMonthReport></OneMonthReport>
                    </div>
                    <div id="ClientReport" class="tab-pane" :class="{ 'active show': activeKey == 2 }" v-if="activeKey == 2">
                        <ClientReport></ClientReport>
                    </div> 
                    <div id="EntryWiseReport" class="tab-pane" :class="{ 'active show': activeKey == 3 }" v-if="activeKey == 3">
                        <EntryWiseReport></EntryWiseReport>
                    </div>
                    <div id="HalfYearly" :key="refreshKey" :ReportName="ReportName" class="tab-pane" :class="{ 'active show': activeKey == 4 }" v-if="activeKey == 4">
                        <OneMonthReport></OneMonthReport>
                    </div>
                    <div id="DailyAttendanceReport" class="tab-pane" :class="{ 'active show': activeKey == 5 }" v-if="activeKey == 5">
                        <ProfitabilityReport></ProfitabilityReport>
                    </div>
                    <div id="UserAliasreport" class="tab-pane" :class="{ 'active show': activeKey == 6 }" v-if="activeKey == 6">
                        <ProjectDetailReport></ProjectDetailReport>
                    </div>
                    <div id="ProjectReport" :key="refreshKey" :ReportName="ReportName" class="tab-pane" :class="{ 'active show': activeKey == 7 }" v-if="activeKey == 7">
                        <OneMonthReport></OneMonthReport>
                    </div>
                    <div id="ProjectWiseReport" class="tab-pane" :class="{ 'active show': activeKey == 8 }" v-if="activeKey == 8">
                        <ProjectWiseReport></ProjectWiseReport>
                    </div>
                    <div id="TimesheetHourlyReport" class="tab-pane" :class="{ 'active show': activeKey == 9 }" v-if="activeKey == 9">
                        <TimesheetHourlyReport></TimesheetHourlyReport>
                    </div>
                    <div id="TrackEntryDetails" class="tab-pane" :class="{ 'active show': activeKey == 10 }" v-if="activeKey == 10">
                        <EntryWiseReport></EntryWiseReport>
                    </div>
                    <div id="UserReport" :key="refreshKey" :ReportName="ReportName" class="tab-pane" :class="{ 'active show': activeKey == 11 }" v-if="activeKey == 11">
                        <OneMonthReport></OneMonthReport>
                    </div>
                    <div id="TimeSheetReport" class="tab-pane" :class="{ 'active show': activeKey == 12 }" v-if="activeKey == 12">
                        <TimeSheetReport></TimeSheetReport>
                    </div>
                    <div id="UserWiseReport" class="tab-pane" :class="{ 'active show': activeKey == 13 }" v-if="activeKey == 13">
                        <UserWiseReport></UserWiseReport>
                    </div>
                    <div id="AppWebSiteTracking" :key="refreshKey"  class="tab-pane" :class="{ 'active show': activeKey == 14 }" v-if="activeKey == 14">
                        <AppWebSiteTracking></AppWebSiteTracking>
                    </div>
                    <div id="UserDetailReport" :key="refreshKey"  class="tab-pane" :class="{ 'active show': activeKey == 15 }" v-if="activeKey == 15">
                        <UserDetailReport></UserDetailReport>
                    </div>
                   
                </div>
            </div>
        </div>
        <!-- right-content End here -->
    </div>
    </template>
<script>
    
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
     import OneMonthReport from "../../views/BIReports/OneMonthReport.vue";
     import ClientReport from "../../views/BIReports/ClientReport.vue";
     import EntryWiseReport from "../../views/BIReports/EntryWiseReport.vue";
     import ProfitabilityReport from "../../views/BIReports/ProfitabilityReport.vue";
     import ProjectDetailReport from "../../views/BIReports/ProjectDetailReport.vue";
     import ProjectWiseReport from "../../views/BIReports/ProjectWiseReport.vue";
     import TimeSheetReport from "./UserTimeSheetDetailReport.vue";
     import UserWiseReport from "../../views/BIReports/UserWiseReport.vue";
     import AppWebSiteTracking from "../../views/BIReports/AppWebSiteTracking.vue";
     import UserDetailReport from "../../views/BIReports/UserDetailReport.vue";
     import TimesheetHourlyReport from "../../views/BIReports/TimesheetHourlyReport.vue";
    export default {
        components: {
            OneMonthReport,
            ClientReport,
            EntryWiseReport,
            ProfitabilityReport,
            ProjectDetailReport,
            ProjectWiseReport,
            TimeSheetReport,
            UserWiseReport,
            AppWebSiteTracking,
            UserDetailReport,
            TimesheetHourlyReport
         },
        data() {
            return {
                activeKey: 0,
                tabNames: [
                    "1 Month",
                    "1 Week",
                    "Client Report",
                    "Entry Wise",
                    "Half Yearly",
                    "Profitability Report",
                    "Project details Report",
                    "Project Report",
                    "Project-Wise",
                    "Timesheet Hourly Report",
                    "Track Entry Details",
                    "User Report",
                    "User Timesheet Detail Report",
                    "User Wise",
                    "App WebSite Tracking",
                    "User Detail Report"
                ],
                searchQuery: "",
                ReportName:"7WEEKS",
                refreshKey: 0,
            };
        },
        mounted() {
            this.activateTab(0);
        },
        created:function(){
            
        },
        computed: {
        filteredTabs() {
            debugger;
            if (!this.searchQuery) {           
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }));
            }
            const query = this.searchQuery.toLowerCase();
            const filtered = this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
    
            if (query.trim() !== '' && filtered.length === 0) {           
                return [{ name: 'No tabs found for "' + this.searchQuery + '"', index: -1, icon: 'no-icon' }];
            }
    
            return filtered;
        },
        activeTabName() {
            return this.tabNames[this.activeKey]; // Returns the name of the currently active tab
        }
    },
    
        methods: {
            getTabIcon(name) {
                switch (name) {
                    case "1 Month":
                        return "fa fa-calendar";
                    case "1 Week":
                        return "fa fa-calendar-o";
                    case "Client Report":
                        return "fa fa-user-circle";
                    case "Entry Wise":
                        return "fa fa-align-justify";
                    case "Half Yearly":
                        return "fa fa-list-alt";
                    case "Profitability Report":
                        return "fa fa-print";
                        case "Project details Report":
                        return "fa fa-folder-o";
                        case "Project Report":
                        return "fa fa-folder-open";
                        case "Project-Wise":
                        return "fa fa-sticky-note";
                        case "Track Entry Details":
                        return "fa fa-file-text";
                        case "User Timesheet Detail Report":
                        return "fa fa-user-o";
                        case "User Report":
                        return "fa fa-columns";
                        case "User Wise":
                        return "fa fa-user-o";
                        case "App WebSite Tracking":
                        return "fa fa-user-o";
                        case "User Detail Report":
                        return "fa fa-user-o";
                        case "Timesheet Hourly Report":
                        return "fa fa-clock-o";
                    default:
                        return "";
                }
            },
            activateTab(index) {
                debugger;
                var vm=this;
                this.activeKey = index;
                vm.refreshKey += 1;
                //this.activeKey==1? vm.Reportname = 'oneMonth': vm.Reportname ='week'
                if(this.activeKey==0){
                    vm.ReportName="7WEEKS"
                }
                else if (this.activeKey==1){
                    vm.ReportName ='WEEKLY'
                }
                else if (this.activeKey==4){
                    vm.ReportName ='7MONTHS'
                }
                else if (this.activeKey==7)
                {
                    vm.ReportName ='ProjectReport'
                }
                else if (this.activeKey==11){
                    vm.ReportName ='WEEKLY'
                }
            },
        },
    };
    </script>
    