<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
</template>
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from '../HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                // FindalLocationArray: [],          
                FormSchema: [{
                        layoutType: "triple",
                        Data: [{
                                astype: "MultiSelectField",
                                label: this.$t("Project"),
                                name: "Project",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Project'),
                                mode: "tag",
                                config: {
                                    options: [],
                                },
                                validationRules: {
                                    "required": true
                                }
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Status"),
                                name: "Status",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Status'),
                                mode: "tag",
                                config: {
                                    options: []
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Channel"),
                                name: "Channel",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Channel'),
                                mode: "tag",
                                config: {
                                    options: [],
    
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Rate"),
                                name: "Rate",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Rate'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Project Rate', value:'Project Rate'}, {name:'Task Rate', value:'Task Rate'},{name:'User Rate', value:'User Rate'},
                                      {name:'User Project Rate', value:'User Project Rate'},{name:'User Task Rate', value:'User Task Rate'} ],
                                  
                                },
                            },
                        ],
                    },
                 
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;
           await vm.GetProjectList();
           await vm.GetChannel();
           await  vm.GetStatusList();
        },
        methods: {
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "profitabilityreport",
                    projectIds: e.Project.length > 0 ? e.Project.map(item => item.value).join(",") : '',
                    channelids: e.Channel.length > 0 ? e.Channel.map(item => item.value).join(",") : '',
                    StatusIds:  e.Status.length > 0 ? e.Status.map(item => item.value).join(",") : '',
                    Rate: e.Rate == "" ? 0 : e.Rate
                   
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },

            GetProjectList :async function () {
                debugger;
            var vm = this;
            var params = `companyId=${vm.companyId}&userId=${vm.userId}&pmIds=&isIncludeNoProject=`;
            DataServices.GetProjectList(params).then((response) => {
                if (response.data != '') {
                    vm.EmployeeData = JSON.parse(response.data.result);
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[0].config.options.push({
                            name: item.PROJECTNAME,
                            value: item.PROJECTID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetChannel :async function () {
            var vm = this;
            await DataServices.GetChannel().then((response) => {
                debugger;
                if (response.data != '') {
                    vm.EmployeeData = response.data;
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.CHANNEL_NAME,
                            value: item.CHANNEL_ID 
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetStatusList: async function () {
            debugger;
                var vm = this;
                var url = `langCode=en&statusType=Project&hasglobal=false`
                await DataServices.GetStatusList(url).then((response) => {
                    if (response.data.length > 0) {
                        var LocationData = response.data;
                        LocationData.forEach(element => {
                            var Obj = {
                                name: element.STATUS,
                                value: element.STATUS_ID
                            }
                            vm.FormSchema[0].Data[1].config.options.push(Obj);
                        });
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },
        }
    };
    </script>
    