<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
</template>
    
    <script>
    import DataServices from "../../services/DataService";
    import ReportViewer from '../HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                // FindalLocationArray: [],          
                FormSchema: [{
                        layoutType: "four",
                        Data: [{
                                astype: "MultiSelectField",
                                label: this.$t("Project"),
                                name: "Project",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Project'),
                                mode: "tag",
                                config: {
                                    options: [],
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Manager"),
                                name: "Manager",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Manager'),
                                mode: "tag",
                                config: {
                                    options: []
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("User"),
                                name: "User",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('User'),
                                mode: "tag",
                                config: {
                                    options: [],
    
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Channel"),
                                name: "Channel",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Channel'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                        ],
                    },
                    {
                    layoutType: "four",
                        Data: [{
                                astype: "TextField",
                                label: this.$t("Tasks"),
                                name: "Tasks",
                                value: "Select Projects to populate Tasks"
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Project Type"),
                                name: "ProjectType",
                                value: "ALL",
                                placeholder: this.$t('Select') + " " + this.$t('ProjectType'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Fixed', value:'Fixed'},{name:'Hourly', value:'Hourly'}],
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Department"),
                                name: "Department",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Department'),
                                config: {
                                    options: [],
    
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Show Data by"),
                                name: "ShowDataby",
                                value: "Showdata",
                                placeholder: this.$t('Select'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Tasks', value:'Tasks'},{name:'Users', value:'Users'}, {name:'Projects', value:'Projects'}],
                                  
                                },
                            },
                            {
                                astype: "SelectField",
                                label: this.$t("Status"),
                                name: "Status",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Manager'),
                                mode: "tag",
                                config: {
                                    options: [{name:'Pending', value:'1'}, {name:'Approved', value:'2'}],
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Client"),
                                name: "Client",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Client'),
                                config: {
                                    options: [],
    
                                },
                                validationRules: {
                                "required": false
                            }
                            },
                        ],
                    },
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;
            await vm.GetProjectList();
            await vm.GetLeaveType();
            await vm.GetUsers();
            await  vm.GetChannel();
            await vm.GetDepartment();
            
        },
        methods: {
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                let myObj = {
                    reportName: "detailedreport",
                    projectIds:  e.Project.length > 0 ? e.Project.map(item => item.value).join(",") : '',
                    DepartmentIds:  e.Department.length > 0 ? e.Department.map(item => item.value).join(",") : '',
                    userIds:  e.User.length > 0 ? e. User.map(item => item.value).join(",") : '',
                    channelids:  e.Channel.length > 0 ? e.Channel.map(item => item.value).join(",") : '',
                    ShowDataBy: e.ShowDataby == "" ? "" : e.ShowDataby ,
                    TimeType: e.ProjectType,
                    ManagerIds:e.Manager.length > 0 ? e.Manager.map(item => item.value).join(",") : '',
                    StatusIds:e.Status == "" ? 0 : e.Status,
                    ClientIds: e.Client == "" ? 0 : e.Client,
                    groupByVal: 'detailedreport' 
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.ReportPath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },
            GetProjectList :async function () {
            var vm = this;
            var params = `companyId=${vm.companyId}&userId=${vm.userId}&pmIds=&isIncludeNoProject=`;
            DataServices.GetProjectList(params).then((response) => {
                if (response.data != '') {
                    vm.EmployeeData = JSON.parse(response.data.result);
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[0].config.options.push({
                            name: item.PROJECTNAME,
                            value: item.PROJECTID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },

        GetLeaveType :async function () {
            var vm = this;
            var params = `CompanyId=${vm.companyId}&loggedUserId=${vm.userId}`;
            await DataServices.GetLeaveTypes(params).then((response) => {
                if (response.data != '') {
                     
                    vm.EmployeeData = response.data;
                    vm.EmployeeData.forEach(item => {
                        vm.FormSchema[0].Data[1].config.options.push({
                            name: item.USER_NAME,
                            value: item.USER_ID
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },      


            GetUsers :async function () {
                 
                 var vm = this;
                 var params = `isType=false&moduleName=ProjectReport`;
                 await DataServices.GetUsers(params).then((response) => {
                     if (response.data != '') {
                          
                         vm.EmployeeData = response.data;
                         vm.EmployeeData.forEach(item => {
                             vm.FormSchema[0].Data[2].config.options.push({
                                 name: item.UserName,
                                 value: item.UserId 
                             })
                         })
                     }
                     vm.$refs.BarcodeReport.UpdateKeyValue();
                 });
             },
     
             GetChannel :async function () {
                 var vm = this;
                 await DataServices.GetChannel().then((response) => {
                     debugger;
                     if (response.data != '') {
                         vm.EmployeeData = response.data;
                         vm.EmployeeData.forEach(item => {
                             vm.FormSchema[0].Data[3].config.options.push({
                                 name: item.CHANNEL_NAME,
                                 value: item.CHANNEL_ID 
                             })
                         })
                     }
                     vm.$refs.BarcodeReport.UpdateKeyValue();
                 });
             },
             
             GetDepartment :async function () {
                 debugger;
                 var vm = this;
                 await DataServices.GetDepartments().then((response) => {
                     debugger;
                     if (response.data != '') {
                         vm.EmployeeData = response.data;
                         vm.EmployeeData.forEach(item => {
                             vm.FormSchema[1].Data[2].config.options.push({
                                 name: item.DEPARTMENT_NAME,
                                 value: item.DEPARTMENT_ID 
                             })
                         })
                     }
                     vm.$refs.BarcodeReport.UpdateKeyValue();
                 });
             },
         
        }
    };
    </script>
    
